{
  "situations": [
    {
      "dialogue": "{{NAME}}, o tanque ficou verde perto da janela. O medidor mostra entrada de CO₂ na água, e há sais minerais dissolvidos enquanto os organismos recebem luz.",
      "imagePrompt": "Aquário pequeno perto de uma janela, água esverdeada por algas, setas simples mostrando luz entrando e CO₂ dissolvido na água, rótulo curto “sais minerais na água”.",
      "options": [
        {
          "feedback": "Correto. As algas usam luz como energia e obtêm matéria do CO₂, da água e dos sais, então se encaixam como produtores.",
          "isCorrect": true,
          "text": "Produtores"
        },
        {
          "feedback": "Não. Consumidores obtêm matéria e energia ingerindo outros seres vivos; a evidência mostra uso de luz e CO₂.",
          "isCorrect": false,
          "text": "Consumidores"
        },
        {
          "feedback": "Não. Decompositores atuam sobre matéria orgânica morta; aqui os organismos estão crescendo com luz e CO₂.",
          "isCorrect": false,
          "text": "Decompositores"
        },
        {
          "feedback": "Não. A luz ajuda como fonte de energia, mas não é matéria nem alimento.",
          "isCorrect": false,
          "text": "Luz como alimento"
        }
      ],
      "question": "Como esses organismos devem ser classificados?"
